const token = $input.first().json.tenant_access_token;
// รับ page_token จาก query string สำหรับ pagination (โหลดเพิ่ม)
const webhookData = $('Webhook Get Customers').first().json;
const incomingPageToken = (webhookData.query && webhookData.query.page_token) ? webhookData.query.page_token : '';
// ไม่ระบุ field_names เพราะ Lark จะ return primary field ไม่ครบถ้า specify
const body = { page_size: 500 };
if (incomingPageToken) body.page_token = incomingPageToken;
return [{ json: { lark_token: token, searchBody: JSON.stringify(body) } }];

const data = $input.first().json;
const items = data.data?.items || [];
// Lark pagination — ส่งกลับไปให้ dashboard โหลดหน้าต่อไปได้
const larkPageToken = data.data?.page_token || null;
const larkHasMore   = !!data.data?.has_more;
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.link) return v.link;
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; if (f.link) return f.link; return f.text || f.name || ''; }
  if (v.text) return v.text;
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const customers = items.map(it => {
  const f = it.fields;
  const shopName   = txt(f['Shop Name']) || txt(f['Customer']) || '';
  const lineUserId = txt(f['C.LINE User ID']) || txt(f['C.LINE ID']) || txt(f['LINE User ID']) || '';
  const phone      = txt(f['Customer Phone 1']) || '';
  const phone2     = txt(f['Customer Phone 2']) || '';
  const contact    = txt(f['Customer Contact 1']) || '';
  const contact2   = txt(f['Customer Contact 2']) || '';
  const mapsUrl    = txt(f['Google Maps URL']) || txt(f['Machine Location']) || '';
  const address    = txt(f['Address']) || '';
  const peakCode   = txt(f['PEAK Code']) || '';
  const custType   = txt(f['Customer Type']) || '';
  const equipType  = txt(f['Equipment Type']) || '';
  const health     = txt(f['Account Status']) || '';
  const zone       = txt(f['Zone']) || '';
  return {
    record_id: it.record_id,
    'Shop Name':          shopName,
    'Customer ID':        txt(f['Customer ID']),
    'Customer Phone 1':   phone,
    'Customer Phone 2':   phone2,
    'Customer Contact 1': contact,
    'Customer Contact 2': contact2,
    'C.LINE User ID':     lineUserId,
    'Google Maps URL':    mapsUrl,
    'Address':            address,
    'PEAK Code':          peakCode,
    'Customer Type':      custType,
    'Equipment Type':     equipType,
    'Account Status':     health,
    shop_name: shopName, line_id: lineUserId, phone: phone, phone2: phone2,
    maps_url: mapsUrl, address: address, contact: contact, contact2: contact2,
    account_health: health, zone: zone
  };
}).filter(c => c['Shop Name']).sort((a, b) => a['Shop Name'].localeCompare(b['Shop Name'], 'th'));
return [{ json: { customers, page_token: larkPageToken, has_more: larkHasMore } }];

const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.link) return v.link;
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; return f.text || f.name || ''; }
  if (v.text) return v.text;
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const technicians = items.map(it => {
  const f = it.fields;
  const staffName = txt(f['์Name']) || txt(f['Name']);
  const techName = txt(f['Tech Name']);
  const lineUserId = txt(f['Tech Line User ID']) || '';
  const lineId = txt(f['Tech Line ID']) || '';
  const role = txt(f['Role']) || '';
  const staffId = txt(f['Staff ID']) || '';
  const phone = txt(f['Staff Phone']) || '';
  const larkId = txt(f['Tech Lark ID']) || '';
  return {
    record_id: it.record_id,
    'Name': staffName,
    'Tech Name': techName,
    'Staff ID': staffId,
    'Role': role,
    'Staff Phone': phone,
    'Tech Lark ID': larkId,
    'Tech Line User ID': lineUserId,
    'Tech Line ID': lineId,
    name: staffName, tech_name: techName, staff_id: staffId,
    line_id: lineUserId, phone: phone, role: role
  };
}).filter(t => t['Name']).sort((a, b) => a['Name'].localeCompare(b['Name'], 'th'));
return [{ json: { technicians } }];

const d = $input.first().json;
const body = d.body || d;
return [{ json: {
  customer_record_id: body.customer_record_id || '',
  machine_record_id:  body.machine_record_id  || '',
  tech_record_id:     body.tech_record_id     || '',
  job_type:           body.job_type           || 'ซ่อม',
  priority:           body.priority           || 'ปกติ',
  scheduled_date:     body.scheduled_date     || '',
  problem:            body.problem            || '',
  note:               body.note               || '',
  source:             'Dashboard'
}}];

// ────────────────────────────────────────────
// Prep T5 Body (manual create from admin dashboard)
// ⚠️ Per 2026-04-18 audit + decision (Option B):
//   • T5.Customer is a LOOKUP field — resolved via Machine link, DO NOT write.
// ⚠️ Per 2026-04-20 live test (rental-cron bug #5):
//   • Lark Link write format = ["rec..."] NOT { link_record_ids: [...] } (legacy object)
//     legacy format = LinkFieldConvFail code 1254067 ทันที
//
// 📌 TECH DEBT (tracked 2026-04-18):
//   Dashboard form ต้องเพิ่ม Machine selector → ส่ง machine_record_id →
//   เพิ่ม Machine write ตรงนี้ → T5.Customer Lookup จะ resolve ได้อัตโนมัติ
//   ปัจจุบัน dashboard ยังไม่ส่ง machine_record_id จึง skip Machine write ไปก่อน
// ────────────────────────────────────────────
const token = $('Get Token [CJ]').first().json.tenant_access_token;
const src   = $('Compute Job No.').first().json;  // 🔧 includes job_no + Parse Body data

let scheduledMs = null;
if (src.scheduled_date) {
  // Bangkok midnight (ไม่งั้น server UTC จะเพี้ยน -7h)
  try { scheduledMs = new Date(src.scheduled_date + 'T00:00:00+07:00').getTime(); } catch(e) {}
  if (isNaN(scheduledMs)) {
    try { scheduledMs = new Date(src.scheduled_date).getTime(); } catch(e) {}
  }
}

const fields = {};
// 🔧 FIXED 2026-04-26: 'นัดแล้ว' is NOT in T5.Status options · Lark would reject
//   T5.Status options = [รอยืนยัน, เสร็จแล้ว, Cancelled, Failed, ถึงแล้ว]
//   Initial schedule state = 'รอยืนยัน' (matches careplan-cron pattern)
fields['Status'] = 'รอยืนยัน';
// 🔧 ADDED 2026-04-27: Job No. = J-YYYYMMDD-XXX (n8n-generated · vendor-portable)
if (src.job_no)      fields['Job No.']        = src.job_no;
// Job Type is MultiSelect (verified 2026-04-20) → must be array even for single value
if (src.job_type)    fields['Job Type']       = Array.isArray(src.job_type) ? src.job_type : [src.job_type];
// 🔧 FIXED 2026-04-27: Map dashboard codes (low/med/high) → T5.Priority options (Low/Medium/High)
//   T5.Priority SingleSelect: [Very Urgent, High, Medium, Low] · case-sensitive · mismatch = silent reject
const PRIORITY_MAP = { low: 'Low', med: 'Medium', high: 'High', urgent: 'Very Urgent' };
if (src.priority)    fields['Priority']       = PRIORITY_MAP[src.priority] || src.priority;
if (src.problem)     fields['Defect']         = src.problem;
// 🔧 FIXED 2026-04-26: T5 has no 'Note' field · use 'Billing Note' for admin remarks
if (src.note)        fields['Billing Note']   = src.note;
// 🔧 FIXED 2026-04-26: T5 has no 'Source' field · use 'Source Ref ID' for tracing
if (src.source)      fields['Source Ref ID']  = src.source;
if (scheduledMs)     fields['Scheduled Date'] = scheduledMs;
// ❌ Removed: Customer write — T5.Customer = Lookup (silent-drop anyway).
// 🔧 FIXED 2026-04-26: Field name = 'Assigned Technician' (T5 schema · SingleLink to T8)
//   Was 'Technician' which doesn't exist · silent-dropped tech assignment
if (src.tech_record_id)     fields['Assigned Technician']  = [src.tech_record_id];
// 🔧 ADDED 2026-04-27: Machine link → T2 (required for Customer Lookup + Job No. formula to resolve)
if (src.machine_record_id)  fields['Machine']              = [src.machine_record_id];
// 🔧 ADDED 2026-04-30: Customer Link → T1 (direct link เพื่อให้ Lookup fields ทำงานทันที)
//   Lark ไม่รองรับ 2-hop Lookup (T5→T2→T1) → ต้อง direct T5→T1 link สำหรับ Phone 1/2/3, LINE ID, Maps URL
if (src.customer_record_id) fields['Customer Link']        = [src.customer_record_id];

return [{ json: { ...src, lark_token: token, createBody: JSON.stringify({ fields }) } }];

const result = $input.first().json;
if (result.code !== 0) {
  return [{ json: { ok: false, error: result.msg || 'Lark API error', code: result.code } }];
}
const record = result.data?.record || {};
return [{ json: {
  ok: true,
  record_id: record.record_id || '',
  job_no:    record.fields?.['Job No.'] || '',
  status:    record.fields?.['Status']  || 'นัดแล้ว',
  message:   'สร้างงานสำเร็จ'
} }];

const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; return f.text || f.name || ''; }
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const jobs = items.map(it => {
  const f = it.fields;
  const created = f['Created Time'] || it.created_time;
  const scheduled = f['Scheduled Date'];
  return {
    record_id: it.record_id,
    job_id: txt(f['Job ID']) || txt(f['Job No.']) || txt(f['job_id']) || it.record_id,
    status: txt(f['Status']) || 'new',
    tech_name: txt(f['Tech Name']) || txt(f['Technician']) || txt(f['tech_name']),
    customer_name: txt(f['Shop Name']) || txt(f['Customer Name']) || txt(f['Customer']),
    job_type: txt(f['Job Type']),
    priority: txt(f['Priority']),
    job_address: txt(f['Job Address']) || txt(f['Address']),
    scheduled_date: typeof scheduled === 'number' ? new Date(scheduled).toISOString() : txt(scheduled),
    timestamp: typeof created === 'number' ? new Date(created).toISOString() : (typeof created === 'string' ? created : null)
  };
});
return [{ json: { jobs } }];

const token = $input.first().json.tenant_access_token;
// วันนี้ 00:00 - 23:59 (UTC+7)
const now = new Date();
const bkkOffset = 7 * 60 * 60 * 1000;
const todayBKK = new Date(Math.floor((now.getTime() + bkkOffset) / 86400000) * 86400000 - bkkOffset);
const from = Math.floor(todayBKK.getTime() / 1000);
const to   = from + 86399;
return [{ json: { lark_token: token, from_ts: from, to_ts: to } }];

const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) { const f = v[0]; if (!f) return ''; return f.text || f.name || String(f); }
  if (v.value) { const vv = v.value; if (typeof vv === 'string') return vv; if (Array.isArray(vv)) { const f = vv[0]; return f?.text || f?.name || ''; } }
  return '';
};
const team = items.map(it => {
  const f = it.fields;
  const nickname  = txt(f['์Name']) || txt(f['Name']);
  const techName  = txt(f['Tech Name']);
  const workSt    = txt(f['Work Status']) || 'หยุด';
  const acctSt    = txt(f['Account Status']);
  const statusMap = { 'เข้างาน': 'working', 'ลา': 'leave', 'หยุด': 'off' };
  const status    = statusMap[workSt] || 'off';
  return { nickname, tech_name: techName, name: nickname, checked_in: status === 'working', check_in_time: null, status, work_status: workSt, acct_status: acctSt };
}).filter(t => t.nickname && t.acct_status !== 'Inactive');
team.sort((a, b) => (b.checked_in ? 1 : 0) - (a.checked_in ? 1 : 0));
return [{ json: { team } }];

const token = $input.first().json.tenant_access_token;
const body = { page_size: 500 };
return [{ json: { lark_token: token, searchBody: JSON.stringify(body) } }];

const items = $input.first().json.data && $input.first().json.data.items ? $input.first().json.data.items : [];
const BLOCKED = ['Machine (Sale)', 'Machine (Rental)'];
function txt(v) {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (v.text) return v.text;
  if (v.value) return v.value;
  if (Array.isArray(v) && v[0]) return txt(v[0]);
  return '';
}
const products = items
  .map(function(r) {
    const f = r.fields || {};
    const name = txt(f['Product Name'] || f['Name'] || '') || Object.values(f)[0] && txt(Object.values(f)[0]) || '';
    const cat  = txt(f['Sub Category'] || f['Category'] || '');
    const price = parseFloat(f['Price'] || f['Unit Price'] || 0) || 0;
    return { name: name, category: cat, price: price };
  })
  .filter(function(p) { return p.name && BLOCKED.indexOf(p.category) === -1; })
  .sort(function(a, b) { return a.name.localeCompare(b.name, 'th'); });
return [{ json: { products: products, total: products.length } }];

const b = $input.first().json.body || $input.first().json;
const parts = (b.parts || []).map(function(p){ return p.name + ' x' + p.qty; }).join(', ');
return [{ json: {
  job_id:           b.job_id           || '',
  tech_name:        b.tech_name        || '',
  customer_line_id: b.customer_line_id || '',
  customer_name:    b.customer_name    || '',
  parts_text:       parts,
  notes:            b.notes            || '',
  photo_count:      b.photo_count      || 0,
  completed_at:     b.completed_at     || new Date().toISOString()
}}];

const token = $('Get Token [Complete]').first().json.tenant_access_token;
const src = $('Parse Complete Body').first().json;
return [{ json: {
  ...src,
  lark_token: token,
  searchBody: JSON.stringify({ filter: { conjunction: 'and', conditions: [{ field_name: 'Job No.', operator: 'is', value: [src.job_id] }] } })
}}];

// ⚠️ Fixed 2026-04-20:
//    เดิมอ่าน 'T4 Refs' (Text field — ไม่มีใน T5 schema) → t4Refs='' เสมอ → isCarePlan=false เสมอ
//    → branch Update T4 ไม่เคยรัน → Last Done Date ไม่ update → เครื่องถูกนัดซ้ำไม่รู้จบ
//    T5 schema จริงใช้ 'Related Care Plan' (DuplexLink → T4).
const res = $input.first().json;
const items = res.data && res.data.items ? res.data.items : [];
const record_id = items.length > 0 ? items[0].record_id : '';
const src = $('Parse Complete Body').first().json;
const token = $('Get Token [Complete]').first().json.tenant_access_token;
// 🔧 FIXED 2026-04-26: 'Note' and 'Photo Count' don't exist in T5
//   'Note' → 'Resolution Summary' (T5 has it · for completion remarks)
//   'Photo Count' → dropped (no equivalent · count via Photo Before/After attachments)
const fields = {
  'Status': 'เสร็จแล้ว',
  'Parts Used': src.parts_text || '',
  'Resolution Summary': src.notes || ''
};
// Extract Related Care Plan (DuplexLink) + Source Ref ID for CarePlan loop closure
function txt(v) { if (!v) return ''; if (typeof v === 'string') return v; if (v.text) return v.text; if (Array.isArray(v)) return v.map(i => typeof i === 'string' ? i : (i.text||'')).join(','); return ''; }
function extractLinkedIds(v) {
  if (!v) return [];
  const arr = Array.isArray(v) ? v : (Array.isArray(v.value) ? v.value : []);
  return arr.map(r => {
    if (typeof r === 'string') return '';
    return r.record_id || (Array.isArray(r.record_ids) ? r.record_ids[0] : r.record_ids) || '';
  }).filter(Boolean);
}
let t4RefIds = [];
let sourceRefId = '';
if (items.length > 0) {
  const f = items[0].fields || {};
  t4RefIds = extractLinkedIds(f['Related Care Plan']);
  sourceRefId = txt(f['Source Ref ID'] || '');
}
const isCarePlan = (sourceRefId === 'AUTO-CAREPLAN' && t4RefIds.length > 0);
return [{ json: { ...src, record_id, lark_token: token, updateBody: JSON.stringify({ fields }), t4_refs: t4RefIds, source_ref_id: sourceRefId, is_careplan: isCarePlan } }];

// ────────────────────────────────────────────
// Search T4 records referenced by this T5
// เพื่อดึง Interval มาคำนวณ Next Due Date ใหม่
// ⚠️ ห้ามระบุ field_names — Lark จะตัด primary field ทิ้ง
// ⚠️ 2026-04-20: t4_refs เปลี่ยนเป็น array แล้ว (เดิมเป็น comma-string)
// ────────────────────────────────────────────
const data = $('Prep Update T5 Complete').first().json;
const t4Refs = Array.isArray(data.t4_refs) ? data.t4_refs : (typeof data.t4_refs === 'string' ? data.t4_refs.split(',').map(s => s.trim()).filter(Boolean) : []);
const token = data.lark_token;

// Lark: search by record IDs — use __id__ filter
const searchBody = JSON.stringify({
  filter: {
    conjunction: 'or',
    conditions: t4Refs.map(id => ({ field_name: '__id__', operator: 'is', value: [id] }))
  },
  page_size: 20
});

return [{ json: { t4_refs: t4Refs, lark_token: token, searchBody, completed_at: data.completed_at } }];

// ────────────────────────────────────────────
// Update T4 after service completion
// ⚠️ Per 2026-04-18 audit:
//   • Next Due Date is a FORMULA → cannot write. Lark recomputes automatically
//     from Last Done Date + Planned Interval (Months) once we update Last Done Date.
//   • Interval (Months) field does NOT exist in T4 → use Planned Interval (Months) only.
//   • Service Item is DuplexLink → read via Filter Stage (Text) instead.
// ⚠️ Per 2026-04-20 live test (rental-cron bugs #2, #4):
//   • Lark Date READ = ms number → ใช้ dateStr() ไม่ใช่ txt().split('T')[0]
//   • Lark Date WRITE = ms number → ใช้ toMs() ไม่ใช่ 'YYYY-MM-DD' string
// Split → 1 item per T4 update.
// ────────────────────────────────────────────
const res = $input.first().json;
const items = (res.data && res.data.items) || [];
const prevData = $('Prep Search T4 Refs').first().json;
const completedAt = prevData.completed_at || new Date().toISOString();
const token = prevData.lark_token;

function numVal(v) {
  if (typeof v === 'number') return v;
  if (!v) return 0;
  const n = Number(typeof v === 'string' ? v : (v.text || v.value || 0));
  return isNaN(n) ? 0 : n;
}

function txt(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.text) return v.text;
  if (Array.isArray(v) && v[0]) { const x = v[0]; return typeof x === 'string' ? x : (x.text || x.name || ''); }
  return '';
}

// Lark Date field = Unix ms number. Convert to YYYY-MM-DD in Bangkok TZ.
function dateStr(v) {
  if (v === null || v === undefined || v === '') return '';
  if (typeof v === 'number') {
    const bkk = new Date(v + 7 * 3600 * 1000);
    const yyyy = bkk.getUTCFullYear();
    const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(bkk.getUTCDate()).padStart(2, '0');
    return yyyy + '-' + mm + '-' + dd;
  }
  const s = typeof v === 'string' ? v : txt(v);
  if (!s) return '';
  return s.split('T')[0].replace(/\//g, '-');
}

// Lark Date write = ms timestamp (Bangkok midnight)
function toMs(dateStrVal) {
  if (!dateStrVal) return null;
  return new Date(dateStrVal + 'T00:00:00+07:00').getTime();
}

// Calculate months between two YYYY-MM-DD dates (rounded)
function monthsBetween(oldStr, newStr) {
  if (!oldStr || !newStr) return 0;
  const a = new Date(oldStr + 'T00:00:00');
  const b = new Date(newStr + 'T00:00:00');
  if (isNaN(a) || isNaN(b)) return 0;
  const days = (b - a) / 86400000;
  return Math.round(days / 30.44); // avg month length
}

// Parse JSON array from string, safely
function parseIntervals(s) {
  if (!s) return [];
  try {
    const arr = JSON.parse(typeof s === 'string' ? s : txt(s));
    return Array.isArray(arr) ? arr.filter(n => typeof n === 'number') : [];
  } catch(e) { return []; }
}

const updates = items.map(it => {
  const f = it.fields || {};
  // Planned Interval is the template baseline + single source of truth for Formula.
  // Default 3 months as sane fallback if template value missing.
  const interval = numVal(f['Planned Interval (Months)']) || 3;
  // completedAt อาจเป็น ISO ยาว → เอาเฉพาะวันที่ (server UTC ISO ยังใกล้พอสำหรับการคำนวณห่างเดือน)
  const completedDate = completedAt.split('T')[0];

  // ── Actual Interval Tracking ──
  // oldLastDone = previous completion date (null on first run)
  // ⚠️ Last Done Date เป็น Date field = ms number → dateStr() แปลงก่อน
  const oldLastDone = dateStr(f['Last Done Date']);
  const actualInterval = monthsBetween(oldLastDone, completedDate);

  // Keep last 3 actual intervals as JSON array string (for trend analysis / override audit)
  const prevIntervals = parseIntervals(txt(f['Last 3 Actual Intervals']));
  let newIntervals = prevIntervals;
  if (actualInterval > 0) {
    newIntervals = [...prevIntervals, actualInterval].slice(-3);
  }

  // ⚠️ DO NOT write 'Next Due Date' — it's a Formula (silent-drop on write).
  // Lark recomputes: Next Due Date = Last Done Date + Planned Interval (Months).
  // ⚠️ Last Done Date เป็น Date field → write = ms (ไม่ใช่ 'YYYY-MM-DD' ไม่งั้น DatetimeFieldConvFail)
  const updateFields = {
    'Last Done Date': toMs(completedDate),
    'Last 3 Actual Intervals': JSON.stringify(newIntervals)
  };

  return {
    record_id: it.record_id,
    stage_number: numVal(f['Stage Number']),
    filter_name: txt(f['Filter Stage']),
