function txt(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.text) return v.text;
  if (v.value && typeof v.value === 'string') return v.value;
  if (Array.isArray(v) && v[0]) {
    const x = v[0];
    return typeof x === 'string' ? x : (x.text || x.name || x.value || '');
  }
  return '';
}

// Lark Date field = Unix ms number. Convert to YYYY-MM-DD in Bangkok TZ.
function dateStr(v) {
  if (v === null || v === undefined || v === '') return '';
  if (typeof v === 'number') {
    const bkk = new Date(v + 7 * 3600 * 1000);
    const yyyy = bkk.getUTCFullYear();
    const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(bkk.getUTCDate()).padStart(2, '0');
    return yyyy + '-' + mm + '-' + dd;
  }
  const s = typeof v === 'string' ? v : txt(v);
  if (!s) return '';
  return s.split('T')[0].replace(/\//g, '-');
}

// Bangkok-aware today (for fallback when Install date empty)
function bkkTodayStr() {
  const bkk = new Date(new Date().getTime() + 7 * 3600 * 1000);
  const yyyy = bkk.getUTCFullYear();
  const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(bkk.getUTCDate()).padStart(2, '0');
  return yyyy + '-' + mm + '-' + dd;
}

const shopName      = txt(f['Shop Name']);
const machineCode   = txt(f['Machine Code']);
const ownershipRaw  = txt(f['Ownership Type']);
const filterSystem1 = txt(f['Filter System 1']);
const customerRaw   = txt(f['Customer']);

// ─── Determine rental vs sale ───
// NOTE: Rental/Sale = billing model only (Included in Rental? flag),
//       physical interval = material chemistry (independent of contract).
const isRental = ownershipRaw === 'เช่า' || ownershipRaw.toLowerCase().includes('rental');

// ─── Determine stage count from Filter System ───
// '3 ขั้นตอน' → 3, '5 ขั้นตอน' → 5, else → 6
const stageMatch = (filterSystem1 || '').match(/(\d+)/);
const maxStage = stageMatch ? parseInt(stageMatch[1]) : 6;

// ─── Install date ───
// ⚠️ Install date อาจเป็น Date field (ms number) — ใช้ dateStr() แปลง ห้ามใช้ txt().split('T')[0]
// (bug ที่เจอใน rental-cron: ms number → string = literal '1793898000000' แล้ว split('T') ก็ไม่ช่วย)
const installRaw = install_date_override || dateStr(f['Install date']) || dateStr(f['Install Date']);
const installDate = installRaw || bkkTodayStr();

// ─── Fallback interval tables (used only if template row missing) ───
// Physics-bound: Stage 4-6 interval doesn't change whether contract is Rental or Sale.
// Only Stage 1-3 differs (Rental bills monthly → visit monthly; Sale pay-per-service).
const FALLBACK_SALE   = { 1: 1, 2: 3, 3: 3, 4: 10, 5: 12, 6: 12 };
const FALLBACK_RENTAL = { 1: 1, 2: 1, 3: 1, 4: 10, 5: 12, 6: 12 };

// ─── RO Stage Templates ───
// Care Type uses confirmed T4 SingleSelect options: Filter Change | Descaling | PM
// All 6 RO stages = cartridge replacement → Filter Change
// ⚠️ name MUST exactly match Lark T4.Filter Stage MultiSelect options
//    (verified 2026-04-20). Spec detail like '10"' / '300 GPD' belongs in T3 catalog,
//    not here — this is a UI label only.
const RO_STAGE_CONFIG = [
  { stage: 1, name: 'Stage 1 - PP Sediment',        t3_code: 'F00001', interval: 1,  alert: 7,  care_type: 'Filter Change' },
  { stage: 2, name: 'Stage 2 - Carbon Block',       t3_code: 'F00002', interval: 3,  alert: 7,  care_type: 'Filter Change' },
  { stage: 3, name: 'Stage 3 - Resin / Softener',   t3_code: 'F00003', interval: 3,  alert: 7,  care_type: 'Filter Change' },
  { stage: 4, name: 'Stage 4 - RO Membrane',        t3_code: 'F00072', interval: 10, alert: 14, care_type: 'Filter Change' },
  { stage: 5, name: 'Stage 5 - Post Carbon',        t3_code: 'F00004', interval: 12, alert: 14, care_type: 'Filter Change' },
  { stage: 6, name: 'Stage 6 - Mineral / Alkaline', t3_code: 'F00005', interval: 12, alert: 14, care_type: 'Filter Change' }
];

// Filter stages based on machine's filter system count
const selectedStages = RO_STAGE_CONFIG.filter(s => s.stage <= maxStage);

// Rental override: Stage 1-3 visits monthly (billing tie-in), Stage 4-6 physics-bound unchanged.
// Care Type stays 'Filter Change' — the physical act doesn't change with contract type.
const stages = isRental
  ? selectedStages.map(s => ({
      ...s,
      interval: FALLBACK_RENTAL[s.stage] || s.interval,
      alert: s.stage <= 3 ? 7 : 14
    }))
  : selectedStages;

// ─── Helper: Add months to date ───
function addMonths(dateStr, months) {
  const d = new Date(dateStr + 'T00:00:00');
  d.setMonth(d.getMonth() + months);
  return d.toISOString().split('T')[0];
}

// ─── Build stage records ───
