  // ⚠️ ห้ามระบุ field_names
});

return [{ json: { ...data, t4CheckBody: searchBody } }];

// ────────────────────────────────────────────
// Filter: skip stages ที่มี T4 อยู่แล้ว (idempotency)
// ────────────────────────────────────────────
const templateData = $('Prep Check Existing T4').first().json;
const stageRecords = templateData.stage_records;
const lark_token = templateData.lark_token;

const t4Res = $input.first().json;
const existingItems = (t4Res.data && t4Res.data.items) || [];

function txt(v) {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (v.text) return v.text;
  if (Array.isArray(v) && v[0]) {
    const x = v[0];
    return typeof x === 'string' ? x : (x.text || x.name || '');
  }
  return '';
}

// Collect existing stage numbers
const existingStages = existingItems.map(it => {
  const f = it.fields || {};
  return parseInt(txt(f['Stage Number']) || '0');
}).filter(n => !isNaN(n) && n > 0);

// Only create stages that don't exist yet
const newStages = stageRecords.filter(s => !existingStages.includes(s.stage));
const skippedStages = stageRecords.filter(s => existingStages.includes(s.stage));

if (newStages.length === 0) {
  return [{ json: {
    has_new: false,
    skipped: skippedStages.length,
    message: 'All ' + skippedStages.length + ' stages already exist in T4',
    lark_token
  } }];
}

return [{ json: {
  has_new: true,
  new_stages: newStages,
  skipped_count: skippedStages.length,
  new_count: newStages.length,
  shop_name: templateData.shop_name,
  machine_code: templateData.machine_code,
  is_rental: templateData.is_rental,
  lark_token
} }];

// ────────────────────────────────────────────
// Split: แตก new_stages array → 1 item per stage
// ────────────────────────────────────────────
const data = $input.first().json;
return data.new_stages.map(s => ({ json: { ...s, lark_token: data.lark_token } }));

// ────────────────────────────────────────────
// Build T4 record body for Lark create
// ⚠️ Fields NOT to write (per 2026-04-20 audit):
//   • Next Due Date       — Formula (Last Done Date + Planned Interval) → auto-compute
//   • Due Status          — Formula (derived from Next Due Date)
//   • Service Item        — DuplexLink → T3 (needs record_id, not code string; filled separately)
//   • Assigned Technician — Link → T8 (unassigned at init; admin sets later)
//   • Lead Time Override  — Number (empty = fallback to Alert Before (Days))
//   • Customer / Location — covered by Machine link + Lookup
// Fields used (confirmed in T4 schema 2026-04-20):
//   Planned Interval (Months) — Number (template baseline, source of truth)
//   Care Type                 — MultiSelect [Filter Change | Descaling | PM]
//   Filter Stage              — MultiSelect [Stage 1..6 - Material]  ← MUST match Lark options exactly
//   Included in Rental        — Checkbox (true if rental contract)
//   CP Status                 — SingleSelect [Pending | Active | Done]  ← no colon!
//   Last Done Date            — Date (write as ms timestamp)
//   Qty per Visit             — Number (default 1; admin tune per machine)
//   Auto Create Ticket        — Checkbox (true = cron auto-schedules T5; false = admin schedules manually)
//   Interval Override Reason  — Text (audit trail for fallback/override)
//   Last 3 Actual Intervals   — Text (JSON array, filled by create-job workflow)
// ⚠️ Bug #7 pattern: ใช้ $input.all().map() ไม่ใช่ first()
//   Split New Stages ส่งมา 1 item/stage (3-6 stages) — first() จะ drop stage 2-6 เงียบๆ
// ⚠️ Lark Date field write = ms number (bug #4 จาก rental-cron) ใช้ toMs()
// ⚠️ Lark Link write = ["rec..."] NOT [{record_id}] (bug #5 จาก rental-cron)
// ────────────────────────────────────────────

// 🔧 FIXED 2026-04-27 (Path D): Last Done = install_date (ไม่ back-date แล้ว)
//   เดิม: Last Done = install - interval → first due = install date → cron trigger ทันที (noise)
//   ใหม่: Last Done = install_date → first due = install + interval (1 cycle full)
//   Install QC visit (post-install QC สำหรับลูกค้าใหม่) แยกเป็น manual T5 จาก dashboard
//   ไม่ผูกกับ T4 cycle — clean decoupling: PM = recurring, QC = one-shot

// Lark Date write = ms timestamp (Bangkok midnight)
function toMs(dateStr) {
  if (!dateStr) return null;
  return new Date(dateStr + 'T00:00:00+07:00').getTime();
}

return $input.all().map(item => {
  const s = item.json;

  const fields = {
    // ── Identifiers ──
    'Care Plan ID':  s.care_plan_id,
    'Stage Number':  s.stage,
    // MultiSelect fields → must be array even for single value
    'Filter Stage':  [s.filter_name],
    'Care Type':     [s.care_type],   // Filter Change | Descaling | PM

    // ── Schedule ──
    // Planned Interval = template baseline (source of truth for Formula).
    // Next Due Date is a Formula — never write; Lark computes from Last Done Date + this.
    // First cycle: install + interval (no back-dating · post-install QC handled separately)
    'Planned Interval (Months)': s.interval,
    'Alert Before (Days)':       s.alert_days,
    'Last Done Date':            toMs(s.install_date),

    // ── Billing model flag (separate from physical interval) ──
    // 🔧 FIXED 2026-04-26: 'Included in Rental' is FORMULA in T4 (auto-computed) · removed write
    //   Lark API rejects writes to formula fields → silent fail (root cause of 'no T4' bug)

    // ── Status ──
    // 🔧 FIXED 2026-04-27 (Path D): 'Active' ที่ init แทน 'Pending'
    //   เดิม: Pending → ติดที่ Pending ตลอดกาล (no transition logic) → data hygiene issue
    //   ใหม่: Active ที่ init = 80% ลูกค้า auto-mode default · admin pause ราย stage ผ่าน Active？ toggle
    // SingleSelect — no colon in field name (schema confirmed 2026-04-20)
    'CP Status': 'Active',

    // ── Active flag (Path D — admin per-stage toggle) ──
    // 🔧 FIXED 2026-04-26: Added Active？ (Checkbox) · default true · full-width '？'
    // 🔧 ACTIVATED 2026-04-27: cron filter ใช้ field นี้แล้ว (ไม่ใช่ dead data)
    //   admin set false → cron skip stage นั้น (ลูกค้า admin-managed / pause ชั่วคราว)
    'Active？':           true,

    // ── Visit defaults ──
    // 🔧 FIXED 2026-04-26: Field name uses full-width '？' (Lark Base auto-conversion)
    'Qty per Visit':       1,
    'Auto Create Ticket？': true,

    // ── Audit (empty at init; filled when fallback/override triggers) ──
    'Interval Override Reason': '',
    'Last 3 Actual Intervals':  '[]'
  };

  // Linked record: Machine → T2 (DuplexLink) — write format = ["rec..."]
  if (s.machine_record_id) {
    fields['Machine'] = [s.machine_record_id];
  }

  const body = JSON.stringify({ fields });
  return { json: { ...s, createBody: body } };
});

// ────────────────────────────────────────────
// Collect all created T4 records → build response
// ────────────────────────────────────────────
const allItems = $input.all();
const created = [], errors = [];

for (const item of allItems) {
  const d = item.json;
  if (d.data && d.data.record) {
    created.push({
      record_id: d.data.record.record_id,
      care_plan_id: d.data.record.fields?.['Care Plan ID'] || '',
      stage: d.data.record.fields?.['Stage Number'] || ''
    });
  } else if (d.code && d.code !== 0) {
    errors.push({ code: d.code, msg: d.msg || 'error' });
  }
}

// Reconstruct source data from Split New Stages
const splitItems = $('Split New Stages').all();
const shopName = splitItems[0]?.json?.shop_name || '';
const machineCode = splitItems[0]?.json?.machine_code || '';
const isRental = splitItems[0]?.json?.is_rental || false;
const skippedCount = $('Idempotency Filter').first().json.skipped_count || 0;

const summary = {
  success: errors.length === 0,
  machine_code: machineCode,
  shop_name: shopName,
  ownership: isRental ? 'Rental' : 'Sale',
  created_count: created.length,
  skipped_count: skippedCount,
  error_count: errors.length,
  created_records: created,
  errors: errors.length > 0 ? errors : undefined
};

return [{ json: summary }];

// All stages already exist
const data = $input.first().json;
return [{ json: { success: true, message: data.message, skipped: data.skipped } }];

const token = $input.first().json.tenant_access_token;
// page_token จาก query string สำหรับ pagination
const webhookData = $('Webhook Get Machines').first().json;
const incomingPageToken = (webhookData.query && webhookData.query.page_token) ? webhookData.query.page_token : '';
// page_size 500 = T2 ~200-400 records โหลดครบใน 1 request
const body = { page_size: 500 };
if (incomingPageToken) body.page_token = incomingPageToken;
// pass-through customer_record_id filter (apply ใน Format Machines แบบ n8n filter)
const customer_record_id = (webhookData.query && webhookData.query.customer_record_id) ? webhookData.query.customer_record_id : '';
return [{ json: { lark_token: token, searchBody: JSON.stringify(body), customer_record_id } }];

const data = $input.first().json;
const items = data.data?.items || [];
const customer_filter = $('Prep Search T2').first().json.customer_record_id || '';
const larkPageToken = data.data?.page_token || null;
const larkHasMore   = !!data.data?.has_more;
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; return f.text || f.name || f.value || ''; }
  if (v.text) return v.text;
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
// link_record_ids extractor — link fields ใน Lark = { link_record_ids: ['rec...'] } หรือ array of objects
const linkIds = (v) => {
  if (!v) return [];
  if (v.link_record_ids && Array.isArray(v.link_record_ids)) return v.link_record_ids;
  if (Array.isArray(v)) return v.map(x => (typeof x === 'object' && x.record_id) ? x.record_id : (typeof x === 'string' ? x : '')).filter(Boolean);
  return [];
};
let machines = items.map(it => {
  const f = it.fields || {};
  const customer_link_ids = linkIds(f['Shop Name']);
  return {
    record_id: it.record_id,
    'Machine Code':     txt(f['Machine Code']),
    'Customer ID':      txt(f['Customer ID']),
    'Customer':         txt(f['Customer']),
    'Equipment Type':   txt(f['Equipment Type']),
    'Filter System 1':  txt(f['Filter System 1']),
    'Machine Status':   txt(f['Machine Status']),
    'Ownership Type':   txt(f['Ownership Type']),
    'Machine Location': txt(f['Machine Location']),
    'Install date':     f['Install date'] || null,
    'Last Service Date': f['Last Service Date'] || null,
    customer_record_ids: customer_link_ids,
    machine_code: txt(f['Machine Code']),
    customer_name: txt(f['Customer']),
    customer_id: txt(f['Customer ID'])
  };
}).filter(m => m['Machine Code'] || m['Customer ID']);
// n8n-side filter (chosen over Lark filter — see ADR/audit notes)
if (customer_filter) {
  machines = machines.filter(m => m.customer_record_ids.includes(customer_filter));
}
machines.sort((a, b) => (a.customer_name || '').localeCompare(b.customer_name || '', 'th') || (a.machine_code || '').localeCompare(b.machine_code || ''));
return [{ json: { ok: true, machines, page_token: larkPageToken, has_more: larkHasMore, count: machines.length } }];

// ────────────────────────────────────────────
// Generate Job No. : J-YYYYMMDD-XXX (sequence per day)
// 🎯 Owned in n8n (not Lark Formula) — vendor-portable.
// Trade-off: race condition possible if 2 requests come ms-apart.
//   Acceptable for admin dashboard (low concurrency).
// ────────────────────────────────────────────
const res = $input.first().json;
const items = res.data?.items || [];

// Bangkok-aware date prefix
const bkk = new Date(Date.now() + 7 * 3600 * 1000);
const yyyy = bkk.getUTCFullYear();
const mm   = String(bkk.getUTCMonth() + 1).padStart(2, '0');
const dd   = String(bkk.getUTCDate()).padStart(2, '0');
const datePrefix = `J-${yyyy}${mm}${dd}-`;

// Extract sequence numbers from existing Job No.s
const seqs = items
  .map(it => {
    const v = it.fields?.['Job No.'];
    let s = '';
    if (typeof v === 'string') s = v;
    else if (Array.isArray(v) && v[0]) s = v[0].text || v[0];
    else if (v?.text) s = v.text;
    else if (v?.value && Array.isArray(v.value) && v.value[0]) s = v.value[0].text || v.value[0];
    return s;
  })
  .filter(s => s && s.startsWith(datePrefix))
  .map(s => parseInt(s.slice(datePrefix.length), 10))
  .filter(n => !isNaN(n));

const nextSeq = (seqs.length ? Math.max(...seqs) : 0) + 1;
const job_no = `${datePrefix}${String(nextSeq).padStart(3, '0')}`;

// Pass through existing Parse Body data + add job_no
const src = $('Parse Body').first().json;
return [{ json: { ...src, job_no, _seq_today: nextSeq, _date_prefix: datePrefix } }];

const src = $('Parse Complete Body').first().json;
const shortUrl = $input.first().json.data || '';

// รวม phone 1, 2, 3 จาก payload (tech.html ส่งมา)
const rawPhones = [
  src.customer_phone  || '',
  src.customer_phone_2 || '',
  src.customer_phone_3 || ''
];

const seen = new Set();
const items = [];
for (const raw of rawPhones) {
  const digits = raw.replace(/\D/g, '');
  if (!/^0[6-9]/.test(digits)) continue; // Thai mobile only
  const intl = '66' + digits.slice(1);
  if (seen.has(intl)) continue;
  seen.add(intl);
  const msg = 'SK ICE: ประเมินงาน ' + src.job_id + ' ได้ที่: ' + shortUrl + ' ขอบคุณครับ 🙏';
  items.push({ json: { sms_recipient: intl, sms_msg: msg } });
}
return items;

const body = $input.first().json.body || $input.first().json;
const job_id  = body.job_id  || '';
const rating  = parseInt(body.rating) || 0;
const comment = body.comment || '';
const tech_name = body.tech_name || '';
const customer_name = body.customer_name || '';
const ts = new Date().toISOString().replace('T',' ').slice(0,19);
return [{ json: { ts, job_id, rating, comment, tech_name, customer_name } }];
